'use client'

import Link from 'next/link'
import { motion } from 'framer-motion'
import { useState } from 'react'
import { FloatingParticles } from '@/src/components/FloatingParticles'

export default function Home() {
  const [isOpening, setIsOpening] = useState(false)

  const containerVariants = {
    hidden: { opacity: 0 },
    visible: {
      opacity: 1,
      transition: {
        staggerChildren: 0.2,
      },
    },
  }

  const itemVariants = {
    hidden: { opacity: 0, y: 20 },
    visible: {
      opacity: 1,
      y: 0,
      transition: {
        duration: 0.6,
        ease: 'easeOut',
      },
    },
  }

  const openingVariants = {
    initial: { opacity: 1, scale: 1, y: 0 },
    opening: {
      opacity: 0,
      scale: 1.5,
      y: 20,
      transition: {
        duration: 0.8,
        ease: 'easeInOut',
      },
    },
  }

  const textOpeningVariants = {
    initial: { opacity: 1, y: 0 },
    opening: {
      opacity: 0,
      y: -20,
      transition: {
        duration: 0.4,
        ease: 'easeOut',
      },
    },
  }

  const handleEnvelopeClick = () => {
    setIsOpening(true)
    setTimeout(() => {
      // Navigate to first wish or create page
      window.location.href = '/wish'
    }, 800)
  }

  return (
    <main className="min-h-screen flex flex-col items-center justify-center p-6 relative overflow-hidden bg-background-light">
      {/* Ambient background glow */}
      <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-[600px] h-[600px] bg-primary/5 rounded-full blur-[100px] pointer-events-none z-0"></div>
      <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-[400px] h-[400px] bg-accent/10 rounded-full blur-[80px] pointer-events-none z-0 mix-blend-multiply"></div>

      {/* Floating Particles */}
      <div className="absolute inset-0 -z-10 pointer-events-none">
        <FloatingParticles />
      </div>

      {/* Main Container */}
      <motion.div
        className="z-10 flex flex-col items-center max-w-[600px] w-full gap-12 sm:gap-16"
        variants={containerVariants}
        initial="hidden"
        animate="visible"
      >
        {/* Header */}
        <motion.div
          className="text-center flex flex-col gap-2"
          variants={textOpeningVariants}
          animate={isOpening ? 'opening' : 'initial'}
        >
          <p className="font-body text-text-muted font-medium tracking-widest uppercase text-sm mb-2">
            A Special Message For You
          </p>
          <h1 className="font-display text-[36px] sm:text-[48px] font-bold leading-tight text-text-main tracking-tight">
            Eid Mubarak
          </h1>
        </motion.div>

        {/* Interactive Envelope Graphic */}
        <motion.div
          className="relative group cursor-pointer"
          onClick={handleEnvelopeClick}
          variants={openingVariants}
          animate={isOpening ? 'opening' : 'initial'}
        >
          {/* Glow effect behind envelope */}
          <div className="absolute inset-0 bg-gradient-to-br from-accent/40 to-primary/40 rounded-xl blur-2xl opacity-0 group-hover:opacity-100 transition-opacity duration-500 scale-110"></div>

          {/* Envelope */}
          <div className="relative w-[180px] h-[120px] sm:w-[240px] sm:h-[160px] transform transition-all duration-500 group-hover:-translate-y-2 animate-float shadow-glow group-hover:shadow-glow-hover rounded-xl bg-surface dark:bg-slate-800 border border-primary/10 overflow-hidden flex items-center justify-center">
            {/* Envelope Flap (Top) */}
            <div className="absolute top-0 left-0 w-full h-1/2 bg-gradient-to-b from-primary/10 to-transparent z-10">
              <svg
                className="w-full h-full text-primary/20"
                data-alt="Envelope flap graphic"
                fill="none"
                viewBox="0 0 240 80"
                xmlns="http://www.w3.org/2000/svg"
              >
                <path
                  d="M0 0L120 70L240 0"
                  stroke="currentColor"
                  strokeWidth="2"
                ></path>
              </svg>
            </div>

            {/* Envelope Body Gradient */}
            <div className="absolute inset-0 bg-gradient-to-br from-accent to-primary opacity-10"></div>

            {/* Decorative Seal */}
            <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-10 h-10 sm:w-12 sm:h-12 bg-surface dark:bg-slate-800 rounded-full shadow-md z-20 flex items-center justify-center border border-primary/20 group-hover:scale-110 group-hover:rotate-12 transition-transform duration-300">
              <span className="material-symbols-outlined text-primary text-xl sm:text-2xl" style={{ fontVariationSettings: "'FILL' 1" }}>
                favorite
              </span>
            </div>

            {/* Envelope Fold Lines */}
            <svg
              className="absolute inset-0 w-full h-full text-primary/10"
              data-alt="Envelope base graphic"
              fill="none"
              viewBox="0 0 240 160"
              xmlns="http://www.w3.org/2000/svg"
            >
              <path d="M0 160L120 70L240 160" stroke="currentColor" strokeWidth="2"></path>
              <path d="M0 0L80 80" stroke="currentColor" strokeWidth="1"></path>
              <path d="M240 0L160 80" stroke="currentColor" strokeWidth="1"></path>
            </svg>
          </div>
        </motion.div>

        {/* CTA Area */}
        <motion.div
          className="flex justify-center w-full px-4"
          variants={itemVariants}
          animate={isOpening ? 'opening' : 'visible'}
        >
          <button
            className="group relative flex items-center justify-center w-full sm:w-[200px] h-14 button-primary"
            onClick={handleEnvelopeClick}
          >
            <span className="relative z-10 flex items-center gap-2">
              Open Letter
              <span className="material-symbols-outlined text-[20px] group-hover:translate-x-1 transition-transform">
                arrow_forward
              </span>
            </span>
          </button>
        </motion.div>
      </motion.div>
    </main>
  )
}
