'use client'

import { motion } from 'framer-motion'
import { useMemo, useState, useEffect } from 'react'

interface Particle {
  id: number
  left: number
  delay: number
  duration: number
  size: number
  opacity: number
}

export function FloatingParticles() {
  const [windowHeight, setWindowHeight] = useState(0)

  // Get window height on client side only
  useEffect(() => {
    setWindowHeight(window.innerHeight)
  }, [])

  // Generate random particles once on mount
  const particles: Particle[] = useMemo(() => {
    return Array.from({ length: 12 }, (_, i) => ({
      id: i,
      left: Math.random() * 100,
      delay: Math.random() * 2,
      duration: 6 + Math.random() * 4, // 6-10 seconds
      size: 2 + Math.random() * 3, // 2-5px
      opacity: 0.3 + Math.random() * 0.4, // 0.3-0.7
    }))
  }, [])

  // Don't render particles until window height is known
  if (windowHeight === 0) {
    return null
  }

  return (
    <>
      {particles.map(particle => (
        <motion.div
          key={particle.id}
          className="absolute rounded-full pointer-events-none"
          style={{
            left: `${particle.left}%`,
            top: '-10px',
            width: `${particle.size}px`,
            height: `${particle.size}px`,
            background: `radial-gradient(circle, rgba(255, 198, 217, ${particle.opacity}) 0%, transparent 70%)`,
            boxShadow: `0 0 ${particle.size * 2}px rgba(255, 198, 217, ${particle.opacity * 0.6})`,
          }}
          animate={{
            y: windowHeight + 20,
            opacity: [particle.opacity, particle.opacity * 0.5, 0],
          }}
          transition={{
            duration: particle.duration,
            delay: particle.delay,
            repeat: Infinity,
            ease: 'easeInOut',
          }}
        />
      ))}
    </>
  )
}
